@@ -6433,7 +6433,19 @@ struct SCEVDbgValueBuilder {
     bool Success = true;
     unsigned EmitOperator = 0;
     for (const auto &Op : CommExpr->operands()) {
+      unsigned Before = LocationOps.size() + Expr.size();
