@@ -6532,13 +6532,21 @@ struct SCEVDbgValueBuilder {

     // Skip pushing arithmetic noops.
     if (!isIdentityFunction(llvm::dwarf::DW_OP_mul, Stride)) {
+      unsigned Before = Expr.size() + LocationOps.size();
       if (!pushSCEV(Stride))
         return false;
+      unsigned After = Expr.size() + LocationOps.size();
+      if (Before == After)
+        return false;
       pushOperator(llvm::dwarf::DW_OP_mul);
     }
     if (!isIdentityFunction(llvm::dwarf::DW_OP_plus, Start)) {
+      unsigned Before = Expr.size() + LocationOps.size();
       if (!pushSCEV(Start))
         return false;
+      unsigned After = Expr.size() + LocationOps.size();
+      if (Before == After)
+        return false;
       pushOperator(llvm::dwarf::DW_OP_plus);
     }
     return true;
